let cachedMap: Map<string, string> | null = null;

/** Parse the packed snapshot into a prefix -> organization map (memoized). */
export function getOuiMap(): Map<string, string> {
  if (cachedMap) return cachedMap;
  const m = new Map<string, string>();
  for (const line of OUI_MA_L_PACKED.split("\n")) {
    if (line.length < 7) continue;
    m.set(line.slice(0, 6), line.slice(6));
  }
  cachedMap = m;
  return m;
}
